     8→/**
     9→ * Props for the VRCanvas component
    10→ */
    11→interface VRCanvasProps {
    12→  /** The child components to render within the VR canvas */
    13→  children?: React.ReactNode;
    14→  /** Whether to enable XR mode by default */
    15→  enableXR?: boolean;
    16→  /** Initial VR mode (vr, 3d, or 2d) */
    17→  mode?: VRMode;
    18→  /** Camera field of view */
    19→  fov?: number;
    20→  /** Camera near plane */
    21→  near?: number;
    22→  /** Camera far plane */
    23→  far?: number;
    24→  /** Background color */
    25→  backgroundColor?: string;
    26→  /** Enable shadows */
    27→  shadows?: boolean;
    28→  /** Custom className for styling */
    29→  className?: string;
    30→  /** Callback when XR session starts */
    31→  onXRSessionStart?: () => void;
    32→  /** Callback when XR session ends */
    33→  onXRSessionEnd?: () => void;
    34→  /** Callback when canvas errors occur */
    35→  onError?: (error: Error) => void;
    36→}
    37→
    38→/**
    39→ * VRCanvas Component
    40→ *
    41→ * Main wrapper component for VR experiences using React Three Fiber and WebXR.
    42→ * Provides a responsive 3D canvas that supports both VR headsets and standard displays.
    43→ *
    44→ * Features:
    45→ * - WebXR integration for VR headset support
    46→ * - Responsive sizing
    47→ * - Fallback for non-VR browsers
    48→ * - Error handling
    49→ * - Configurable camera and rendering settings
    50→ *
    51→ * @example
    52→ * ```tsx
    53→ * <VRCanvas enableXR mode="vr">
    54→ *   <VRScene />
    55→ *   <VRHotspots />
    56→ * </VRCanvas>
    57→ * ```
    58→ */
    59→export function VRCanvas({
    60→  children,
    61→  enableXR = true,
    62→  mode = '3d',
    63→  fov = 75,
    64→  near = 0.1,
    65→  far = 1000,
    66→  backgroundColor = '#000000',
    67→  shadows = false,
    68→  className = '',
    69→  onXRSessionStart,
    70→  onXRSessionEnd,
    71→  onError,
    72→}: VRCanvasProps) {
    73→  const [xrStore] = useState(() => createXRStore());
    74→  const [hasError, setHasError] = useState(false);
    75→
    76→  // Handle XR session events
    77→  useEffect(() => {
    78→    if (!enableXR) return;
    79→
    80→    const handleSessionStart = () => {
    81→      onXRSessionStart?.();
    82→    };
    83→
    84→    const handleSessionEnd = () => {
    85→      onXRSessionEnd?.();
    86→    };
    87→
    88→    // Subscribe to XR store events
    89→    const unsubscribe = xrStore.subscribe((state) => {
    90→      if (state.session && !state.session.ended) {
    91→        handleSessionStart();
    92→      } else if (state.session?.ended) {
    93→        handleSessionEnd();
    94→      }
    95→    });
    96→
    97→    return () => {
    98→      unsubscribe();
    99→    };
   100→  }, [enableXR, xrStore, onXRSessionStart, onXRSessionEnd]);

